/* BTAccordion styles — Figma 2473:2493
 *
 * BTAccordion is the group wrapper; BTAccordionItem is the individual panel.
 * Default visual only: separator-based, no card chrome.
 * For card-style panels, see BTAccordionCard.css.
 *
 * Architecture:
 *   .bt-accordion-group          — group wrapper (BTAccordion root)
 *   .bt-accordion                — single item root (BTAccordionItem)
 *   .bt-accordion--open          — currently expanded state
 *   .bt-accordion--disabled      — non-interactive
 *   .bt-accordion__header        — clickable trigger row
 *   .bt-accordion__header--static — non-interactive header (no child slot)
 *   .bt-accordion__title-wrap    — flex-col wrapper for title + subtext
 *   .bt-accordion__title         — primary label
 *   .bt-accordion__subtext       — secondary label
 *   .bt-accordion__chevron       — rotating arrow icon
 *   .bt-accordion__body          — CSS-grid height animating wrapper
 *   .bt-accordion__body-inner    — overflow:hidden inner
 *   .bt-accordion__body-content  — padding wrapper
 *   .bt-accordion__separator     — 1px divider
 */

/* ── Group wrapper ───────────────────────────────────────────────────────── */

.bt-accordion-group {
  display: flex;
  flex-direction: column;
  width: 100%;
}

/* ── Single item root ────────────────────────────────────────────────────── */

.bt-accordion {
  display: flex;
  flex-direction: column;
  width: 100%;
  box-sizing: border-box;
}

/* Disabled */
.bt-accordion--disabled {
  opacity: 0.5;
  pointer-events: none;
}

/* ── Header button ───────────────────────────────────────────────────────── */

.bt-accordion__header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--space-sm);
  width: 100%;
  padding: 8px 0; /* default variant: 8px vertical, no horizontal */
  background: none;
  border: none;
  cursor: pointer;
  user-select: none;
  text-align: start;
  transition: background 0.15s ease;
}

.bt-accordion__header:focus-visible {
  outline: 2px solid var(--color-brand-primary);
  outline-offset: 2px;
  border-radius: var(--radius-sm);
}

/* ── Static header — no chevron, no cursor: pointer ─────────────────────── */

.bt-accordion__header--static {
  display: flex;
  align-items: flex-start;
  gap: var(--space-sm);
  width: 100%;
  padding: 8px 0;
  text-align: start;
}

/* ── Title + subtext column ──────────────────────────────────────────────── */

.bt-accordion__title-wrap {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  flex: 1;
  min-width: 0;
}

/* ── Title ───────────────────────────────────────────────────────────────── */

.bt-accordion__title {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm); /* 14px */
  font-weight: var(--typography-font-weight-medium); /* 500 */
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  margin: 0;
}

/* ── Subtext ─────────────────────────────────────────────────────────────── */

.bt-accordion__subtext {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs); /* 12px */
  font-weight: var(--typography-font-weight-medium); /* 500 */
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  margin: 0;
}

/* ── Chevron ─────────────────────────────────────────────────────────────── */

.bt-accordion__chevron {
  flex-shrink: 0;
  width: 16px;
  height: 16px;
  margin-top: var(--space-2xs);
  color: var(--text-secondary);
  display: flex;
  align-items: center;
  justify-content: center;
  transition: transform 0.25s cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-accordion--open .bt-accordion__chevron {
  transform: rotate(180deg);
}

/* ── Animated body — CSS grid height trick ───────────────────────────────── */

.bt-accordion__body {
  display: grid;
  grid-template-rows: 0fr;
  transition: grid-template-rows 0.28s cubic-bezier(0.4, 0, 0.2, 1);
  overflow: hidden;
}

.bt-accordion--open .bt-accordion__body {
  grid-template-rows: 1fr;
}

.bt-accordion__body-inner {
  min-height: 0;
}

/* Small bottom padding before the separator */
.bt-accordion__body-content {
  padding-bottom: var(--space-sm);
}

/* ── Separator ───────────────────────────────────────────────────────────── */

.bt-accordion__separator {
  height: 1px;
  background: var(--border-primary);
  width: 100%;
  flex-shrink: 0;
}

/* ── Disabled text colors ────────────────────────────────────────────────── */

.bt-accordion--disabled .bt-accordion__title {
  color: var(--text-disabled);
}

.bt-accordion--disabled .bt-accordion__subtext {
  color: var(--text-disabled);
}

/**
 * BTAccordion types — Figma node 2473:2493
 * https://www.figma.com/design/WANr9drWYNYbMPuT2sMeHi/?node-id=2473-2493
 */

export type BTAccordionType = 'single' | 'multiple';

/** Props for the BTAccordion group wrapper. */
export interface BTAccordionProps {
  /**
   * Controls whether one or many items can be open simultaneously.
   * @default 'single'
   */
  type?: BTAccordionType;
  /**
   * The value (key) of the currently open item (single) or open items (multiple).
   * `null` means all items are collapsed (single mode).
   * `[]` means all items are collapsed (multiple mode).
   * Bind with v-model:value.
   */
  value?: string | null | string[];
  /** Additional CSS class on the root element. */
  class?: string;
}

/** Props for a single BTAccordionItem. subtext is a named slot. */
export interface BTAccordionItemProps {
  /** Unique key identifying this item within the group. */
  value: string;
  /** Header title text. */
  title: string;
  /** Disable interaction for this item. */
  disabled?: boolean;
  /**
   * Show the 1px separator line below this item.
   * @default true
   */
  hasSeparator?: boolean;
}

/** Props for a self-contained BTAccordionCard. subtext is a named slot. */
export interface BTAccordionCardProps {
  /** Card header title text. */
  title: string;
  /** Plain subtext below the title. Use the #subtext slot for rich content. */
  subtext?: string;
  /** When true, the card is non-interactive and dimmed. */
  disabled?: boolean;
  /** Controlled expanded state — bind with v-model. */
  modelValue?: boolean;
  /** Initial expanded state (uncontrolled). */
  initiallyExpanded?: boolean;
}

/** Shape of the context provided by BTAccordion to BTAccordionItem children. */
export interface BTAccordionContext {
  isItemOpen: (value: string) => boolean;
  toggle: (value: string) => void;
}

/* BTAccordionCard styles — Figma 2481:6923
 *
 * Self-contained expandable card with its own header (title + chevron).
 * Body has padding: 0 16px 16px (no top, 16px horizontal + bottom) —
 * nested BTAccordion items provide their own top spacing via 8px header padding.
 * The 16px horizontal aligns item text with the card header title.
 * The 16px bottom gives breathing room before the card edge.
 *
 * Architecture:
 *   .bt-accordion-card               — card root (bg + border + radius-sm)
 *   .bt-accordion-card--open         — expanded state
 *   .bt-accordion-card--disabled     — non-interactive + dimmed
 *   .bt-accordion-card__header       — clickable trigger row (constant padding)
 *   .bt-accordion-card__header--static — non-interactive header (no body slot)
 *   .bt-accordion-card__title-wrap   — flex-col for title + subtext
 *   .bt-accordion-card__title        — 16px/bold primary label
 *   .bt-accordion-card__subtext      — 12px/medium secondary label
 *   .bt-accordion-card__chevron      — rotating arrow icon
 *   .bt-accordion-card__body         — CSS-grid height animating wrapper
 *   .bt-accordion-card__body-inner   — overflow:hidden inner
 *   .bt-accordion-card__body-content — always-on padding (0 16px 16px)
 */

/* ── Card root ───────────────────────────────────────────────────────────── */

.bt-accordion-card {
  background: var(--bg-primary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm); /* 6px — Figma radius.sm */
  display: flex;
  flex-direction: column;
  width: 100%;
  box-sizing: border-box;
}

.bt-accordion-card--disabled {
  opacity: 0.5;
  pointer-events: none;
}

/* ── Header button ───────────────────────────────────────────────────────── */

.bt-accordion-card__header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--space-sm);
  width: 100%;
  padding: 12px 16px; /* always 12px top/bottom — does NOT change on expand */
  background: none;
  border: none;
  cursor: pointer;
  user-select: none;
  text-align: start;
}

.bt-accordion-card__header:focus-visible {
  outline: 2px solid var(--color-brand-primary);
  outline-offset: -2px;
}

/* ── Static header — no chevron, no cursor: pointer ─────────────────────── */

.bt-accordion-card__header--static {
  display: flex;
  align-items: flex-start;
  padding: 12px 16px;
  text-align: start;

}

/* ── Title + subtext column ──────────────────────────────────────────────── */

.bt-accordion-card__title-wrap {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  flex: 1;
  min-width: 0;
}

/* ── Title ───────────────────────────────────────────────────────────────── */

.bt-accordion-card__title {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-md); /* 16px */
  font-weight: var(--typography-font-weight-bold); /* 700 */
  line-height: var(--typography-line-height-sm);
  color: var(--text-primary);
  margin: 0;
}

/* ── Subtext ─────────────────────────────────────────────────────────────── */

.bt-accordion-card__subtext {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs); /* 12px */
  font-weight: var(--typography-font-weight-medium); /* 500 */
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  margin: 0;
}

/* ── Chevron ─────────────────────────────────────────────────────────────── */

.bt-accordion-card__chevron {
  flex-shrink: 0;
  width: 16px;
  height: 16px;
  margin-top: var(--space-2xs);
  color: var(--text-secondary);
  display: flex;
  align-items: center;
  justify-content: center;
  transition: transform 0.25s cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-accordion-card--open .bt-accordion-card__chevron {
  transform: rotate(180deg);
}

/* ── Animated body — 3-layer CSS grid height trick ───────────────────────── */
/*
 * Flutter SizeTransition equivalent:
 *   body         → grid 0fr↔1fr + overflow:hidden  (clips body-inner height)
 *   body-inner   → min-height:0 + overflow:hidden  (clips body-content)
 *   body-content → always-on padding               (no class toggle = smooth)
 *
 * Why 3 layers: overflow:hidden never clips an element's OWN padding box.
 * Padding must be on a CHILD so the parent's overflow:hidden can clip it.
 * Without body-content, body-inner's own padding bleeds through when 0fr.
 */

.bt-accordion-card__body {
  display: grid;
  grid-template-rows: 0fr;
  transition: grid-template-rows 0.28s cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-accordion-card--open .bt-accordion-card__body {
  grid-template-rows: 1fr;
}

.bt-accordion-card__body-inner {
  min-height: 0;
  overflow: hidden;
}

.bt-accordion-card__body-content {
  /* 16px horizontal aligns nested BTAccordionItem text with the card header title.
   * 16px bottom gives breathing room before the card edge.
   * No top padding — accordion items provide their own top spacing
   * via their 8px header padding. */
  padding: 0 var(--space-lg) var(--space-lg);
}

/* ── Disabled text colors ────────────────────────────────────────────────── */

.bt-accordion-card--disabled .bt-accordion-card__title {
  color: var(--text-disabled);
}

.bt-accordion-card--disabled .bt-accordion-card__subtext {
  color: var(--text-disabled);
}

export { default as BTAccordion } from './BTAccordion.vue';
export { default as BTAccordionCard } from './BTAccordionCard.vue';
export { default as BTAccordionItem } from './BTAccordionItem.vue';
export type {
  BTAccordionProps,
  BTAccordionCardProps,
  BTAccordionItemProps,
  BTAccordionType,
} from './BTAccordion.types';
